class Solution(object):
    def longestPalindromicSubsequence(self, s, k):
        n = len(s)

        def cyclic_dist(a, b):
            d = abs(ord(a) - ord(b))
            return min(d, 26 - d)

        # dp[i][j][c] = longest palindromic subsequence in s[i..j] with cost <= c
        # But k can be 200 and n=200, so dp is 200*200*201 ~ 8M entries.
        from functools import lru_cache

        @lru_cache(maxsize=None)
        def dp(i, j, budget):
            if i > j:
                return 0
            if i == j:
                return 1
            best = max(dp(i+1, j, budget), dp(i, j-1, budget))
            cost = cyclic_dist(s[i], s[j])
            if cost <= budget:
                best = max(best, dp(i+1, j-1, budget - cost) + 2)
            return best

        return dp(0, n-1, k)
